const files = {
  "app/admin/users/actions.ts": "'use server'\n\nimport { revalidatePath } from 'next/cache'\nimport { createAdminClient } from '@/lib/supabase/admin'\nimport { generateTempPassword } from '@/lib/utils'\n\nexport async function createStudent(formData: FormData) {\n  const email     = formData.get('email')     as string\n  const fullName  = formData.get('full_name') as string\n  const courseId  = formData.get('course_id') as string\n  const expiresAt = formData.get('expires_at') as string\n\n  const admin = createAdminClient()\n  const tempPassword = generateTempPassword()\n\n  const { data: authUser, error: authError } = await admin.auth.admin.createUser({\n    email, password: tempPassword, email_confirm: true,\n  })\n  if (authError) return { error: authError.message }\n\n  const { error: profileError } = await admin.from('users').insert({\n    auth_id: authUser.user.id,\n    email, full_name: fullName,\n    role: 'student', status: 'active',\n  })\n  if (profileError) return { error: profileError.message }\n\n  if (courseId) {\n    const { data: profile } = await admin\n      .from('users').select('id').eq('auth_id', authUser.user.id).single()\n    if (profile) {\n      await admin.from('enrollments').insert({\n        user_id: profile.id, course_id: courseId,\n        expires_at: expiresAt || null,\n      })\n    }\n  }\n\n  revalidatePath('/admin/users')\n  return { success: true, tempPassword }\n}\n\nexport async function toggleUserStatus(userId: string, currentStatus: string) {\n  const admin = createAdminClient()\n  const newStatus = currentStatus === 'active' ? 'inactive' : 'active'\n  const { data: profile } = await admin.from('users').select('auth_id').eq('id', userId).single()\n  const { error } = await admin.from('users').update({ status: newStatus }).eq('id', userId)\n  if (error) return { error: error.message }\n  if (newStatus === 'inactive' && profile?.auth_id) {\n    try { await admin.auth.admin.signOut(profile.auth_id, 'global') } catch {}\n  }\n  revalidatePath('/admin/users')\n  return { success: true }\n}\n\nexport async function updateUserTier(userId: string, tier: number) {\n  const admin = createAdminClient()\n  const { error } = await admin.from('users').update({ tier }).eq('id', userId)\n  if (error) return { error: error.message }\n  revalidatePath('/admin/users')\n  return { success: true }\n}\n\nexport async function importStudentsFromCSV(\n  rows: Array<{ email: string; full_name: string; course_id?: string; expires_at?: string }>\n) {\n  const results = []\n  for (const row of rows) {\n    const fd = new FormData()\n    fd.set('email', row.email)\n    fd.set('full_name', row.full_name)\n    if (row.course_id) fd.set('course_id', row.course_id)\n    if (row.expires_at) fd.set('expires_at', row.expires_at)\n    results.push({ ...row, ...await createStudent(fd) })\n  }\n  return results\n}\n",
  "app/admin/users/CreateUserModal.tsx": "'use client'\n\nimport { useState, useTransition } from 'react'\nimport { createStudent } from './actions'\nimport { X, Copy, Check } from 'lucide-react'\n\ninterface CreatedInfo { name: string; email: string; password: string }\n\nexport default function CreateUserModal({ onClose }: { onClose: () => void }) {\n  const [form, setForm]       = useState({ email: '', full_name: '', expires_at: '' })\n  const [error, setError]     = useState('')\n  const [created, setCreated] = useState<CreatedInfo | null>(null)\n  const [copied, setCopied]   = useState(false)\n  const [isPending, start]    = useTransition()\n\n  function set(k: string, v: string) { setForm(f => ({ ...f, [k]: v })) }\n\n  function handleSubmit(e: React.FormEvent) {\n    e.preventDefault(); setError('')\n    const fd = new FormData()\n    Object.entries(form).forEach(([k, v]) => { if (v) fd.set(k, v) })\n    start(async () => {\n      const res = await createStudent(fd)\n      if (res.error) { setError(res.error); return }\n      setCreated({ name: form.full_name, email: form.email, password: res.tempPassword ?? '' })\n    })\n  }\n\n  function copyAll() {\n    if (!created) return\n    navigator.clipboard.writeText(`Email: ${created.email}\\nM\u1eadt kh\u1ea9u: ${created.password}`)\n    setCopied(true); setTimeout(() => setCopied(false), 2000)\n  }\n\n  return (\n    <div className=\"modal-backdrop\">\n      <div className=\"modal w-full max-w-md\">\n        <div className=\"flex items-center justify-between mb-5\">\n          <h2 className=\"text-base font-semibold text-gray-900\">\n            {created ? 'T\u1ea1o t\u00e0i kho\u1ea3n th\u00e0nh c\u00f4ng' : 'Th\u00eam h\u1ecdc vi\u00ean m\u1edbi'}\n          </h2>\n          <button onClick={onClose} className=\"p-1 text-gray-400 hover:text-gray-600\"><X size={18}/></button>\n        </div>\n\n        {created ? (\n          <div className=\"space-y-4\">\n            <div className=\"bg-emerald-50 border border-emerald-200 rounded-xl p-5 space-y-3\">\n              <p className=\"text-sm font-semibold text-emerald-800\">\n                \u2705 \u0110\u00e3 t\u1ea1o t\u00e0i kho\u1ea3n cho <span className=\"font-bold\">{created.name}</span>\n              </p>\n              <div className=\"bg-white rounded-lg border border-emerald-100 divide-y divide-emerald-100\">\n                <div className=\"px-4 py-3\">\n                  <p className=\"text-xs text-gray-400 mb-0.5\">Email</p>\n                  <p className=\"text-sm font-mono text-gray-900\">{created.email}</p>\n                </div>\n                <div className=\"px-4 py-3\">\n                  <p className=\"text-xs text-gray-400 mb-0.5\">M\u1eadt kh\u1ea9u t\u1ea1m</p>\n                  <p className=\"text-lg font-mono font-bold text-gray-900 tracking-widest\">{created.password}</p>\n                </div>\n              </div>\n            </div>\n            <p className=\"text-xs text-amber-700 bg-amber-50 border border-amber-200 rounded-xl px-4 py-3\">\n              \u26a0\ufe0f L\u01b0u th\u00f4ng tin ngay \u2014 m\u1eadt kh\u1ea9u s\u1ebd kh\u00f4ng hi\u1ec3n th\u1ecb l\u1ea1i sau khi \u0111\u00f3ng.\n            </p>\n            <div className=\"flex gap-3\">\n              <button onClick={copyAll} className=\"btn-secondary flex-1\">\n                {copied ? <><Check size={14}/> \u0110\u00e3 copy!</> : <><Copy size={14}/> Copy th\u00f4ng tin</>}\n              </button>\n              <button onClick={onClose} className=\"btn-primary flex-1 justify-center\">\u0110\u00f3ng</button>\n            </div>\n          </div>\n        ) : (\n          <>\n            {error && <div className=\"alert-error mb-4\">{error}</div>}\n            <form onSubmit={handleSubmit} className=\"space-y-4\">\n              <div>\n                <label className=\"label\">H\u1ecd v\u00e0 t\u00ean *</label>\n                <input className=\"input\" placeholder=\"Nguy\u1ec5n V\u0103n A\"\n                  value={form.full_name} onChange={e => set('full_name', e.target.value)} required/>\n              </div>\n              <div>\n                <label className=\"label\">Email *</label>\n                <input className=\"input\" type=\"email\" placeholder=\"student@example.com\"\n                  value={form.email} onChange={e => set('email', e.target.value)} required/>\n              </div>\n              <div>\n                <label className=\"label\">Ng\u00e0y h\u1ebft h\u1ea1n</label>\n                <input className=\"input\" type=\"date\"\n                  value={form.expires_at} onChange={e => set('expires_at', e.target.value)}/>\n                <p className=\"text-xs text-gray-400 mt-1\">\u0110\u1ec3 tr\u1ed1ng n\u1ebfu kh\u00f4ng gi\u1edbi h\u1ea1n</p>\n              </div>\n              <div className=\"flex gap-3 pt-2\">\n                <button type=\"button\" onClick={onClose} className=\"btn-secondary flex-1\">Hu\u1ef7</button>\n                <button type=\"submit\" disabled={isPending} className=\"btn-primary flex-1 justify-center\">\n                  {isPending ? '\u0110ang t\u1ea1o\u2026' : 'T\u1ea1o t\u00e0i kho\u1ea3n'}\n                </button>\n              </div>\n            </form>\n            <p className=\"text-xs text-gray-400 mt-4\">M\u1eadt kh\u1ea9u t\u1ea1m s\u1ebd hi\u1ec3n th\u1ecb ngay tr\u00ean m\u00e0n h\u00ecnh sau khi t\u1ea1o.</p>\n          </>\n        )}\n      </div>\n    </div>\n  )\n}\n",
  "components/shared/AdminSidebar.tsx": "'use client'\n\nimport Link from 'next/link'\nimport { usePathname, useRouter } from 'next/navigation'\nimport { createClient } from '@/lib/supabase/client'\nimport { BookOpen, Users, LayoutDashboard, HelpCircle, ClipboardList, LogOut } from 'lucide-react'\n\nconst NAV = [\n  { href: '/admin/dashboard',   label: 'Dashboard',  icon: LayoutDashboard },\n  { href: '/admin/users',       label: 'H\u1ecdc vi\u00ean',   icon: Users },\n  { href: '/admin/questions',   label: 'C\u00e2u h\u1ecfi',    icon: HelpCircle },\n  { href: '/admin/assignments', label: 'B\u00e0i t\u1eadp',    icon: ClipboardList },\n]\n\nexport default function AdminSidebar() {\n  const pathname = usePathname()\n  const router   = useRouter()\n\n  async function logout() {\n    await createClient().auth.signOut()\n    router.push('/login')\n    router.refresh()\n  }\n\n  return (\n    <aside className=\"w-60 shrink-0 h-screen sticky top-0 bg-white border-r border-gray-200 flex flex-col\">\n      <div className=\"px-5 py-5 border-b border-gray-100\">\n        <div className=\"flex items-center gap-2.5\">\n          <div className=\"w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center\">\n            <BookOpen className=\"w-4 h-4 text-white\" />\n          </div>\n          <div>\n            <div className=\"font-bold text-gray-900 text-sm leading-none\">SAT Platform</div>\n            <div className=\"text-xs text-gray-400 mt-0.5\">Admin Panel</div>\n          </div>\n        </div>\n      </div>\n      <nav className=\"flex-1 px-3 py-4 space-y-0.5\">\n        {NAV.map(({ href, label, icon: Icon }) => {\n          const active = pathname === href || pathname.startsWith(href + '/')\n          return (\n            <Link key={href} href={href}\n              className={`nav-item ${active ? 'nav-item-active' : 'nav-item-default'}`}>\n              <Icon size={17} />\n              <span>{label}</span>\n            </Link>\n          )\n        })}\n      </nav>\n      <div className=\"px-3 py-4 border-t border-gray-100\">\n        <button onClick={logout} className=\"nav-item nav-item-default w-full\">\n          <LogOut size={17} />\n          <span>\u0110\u0103ng xu\u1ea5t</span>\n        </button>\n      </div>\n    </aside>\n  )\n}\n",
  "app/admin/assignments/actions.ts": "'use server'\n\nimport { revalidatePath } from 'next/cache'\nimport { createAdminClient } from '@/lib/supabase/admin'\n\nexport async function createAssignment(formData: FormData) {\n  const admin = createAdminClient()\n  const { data, error } = await admin.from('assignments').insert({\n    title:       formData.get('title')       as string,\n    description: formData.get('description') as string || null,\n    due_date:    formData.get('due_date')    as string || null,\n  }).select('id').single()\n  if (error) return { error: error.message }\n  revalidatePath('/admin/assignments')\n  return { success: true, id: data.id }\n}\n\nexport async function deleteAssignment(id: string) {\n  const admin = createAdminClient()\n  const { error } = await admin.from('assignments').delete().eq('id', id)\n  if (error) return { error: error.message }\n  revalidatePath('/admin/assignments')\n  return { success: true }\n}\n\nexport async function addQuestionToAssignment(assignmentId: string, questionId: string) {\n  const admin = createAdminClient()\n  const { data: existing } = await admin\n    .from('assignment_questions')\n    .select('id').eq('assignment_id', assignmentId).eq('question_id', questionId).single()\n  if (existing) return { error: 'C\u00e2u h\u1ecfi \u0111\u00e3 c\u00f3 trong b\u00e0i t\u1eadp n\u00e0y' }\n\n  const { data: maxPos } = await admin\n    .from('assignment_questions').select('position')\n    .eq('assignment_id', assignmentId).order('position', { ascending: false }).limit(1).single()\n\n  const { error } = await admin.from('assignment_questions').insert({\n    assignment_id: assignmentId,\n    question_id:   questionId,\n    position:      (maxPos?.position ?? -1) + 1,\n  })\n  if (error) return { error: error.message }\n  revalidatePath(`/admin/assignments/${assignmentId}`)\n  return { success: true }\n}\n\nexport async function removeQuestionFromAssignment(assignmentId: string, questionId: string) {\n  const admin = createAdminClient()\n  const { error } = await admin.from('assignment_questions')\n    .delete().eq('assignment_id', assignmentId).eq('question_id', questionId)\n  if (error) return { error: error.message }\n  revalidatePath(`/admin/assignments/${assignmentId}`)\n  return { success: true }\n}\n\nexport async function updateAssignment(id: string, formData: FormData) {\n  const admin = createAdminClient()\n  const { error } = await admin.from('assignments').update({\n    title:       formData.get('title')       as string,\n    description: formData.get('description') as string || null,\n    due_date:    formData.get('due_date')    as string || null,\n  }).eq('id', id)\n  if (error) return { error: error.message }\n  revalidatePath('/admin/assignments')\n  revalidatePath(`/admin/assignments/${id}`)\n  return { success: true }\n}\n",
  "app/admin/assignments/page.tsx": "import { createClient } from '@/lib/supabase/server'\nimport { formatDate } from '@/lib/utils'\nimport Link from 'next/link'\nimport { Plus, ClipboardList, Trash2 } from 'lucide-react'\nimport DeleteAssignmentBtn from './DeleteAssignmentBtn'\n\nexport default async function AdminAssignmentsPage() {\n  const supabase = await createClient()\n  const { data: assignments } = await supabase\n    .from('assignments')\n    .select('id, title, description, due_date, created_at, assignment_questions(count)')\n    .order('created_at', { ascending: false })\n\n  return (\n    <div className=\"p-6 max-w-5xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <h1 className=\"page-title\">Qu\u1ea3n l\u00fd b\u00e0i t\u1eadp</h1>\n          <p className=\"page-subtitle\">{assignments?.length ?? 0} b\u00e0i t\u1eadp</p>\n        </div>\n        <Link href=\"/admin/assignments/new\" className=\"btn-primary\">\n          <Plus size={15}/> T\u1ea1o b\u00e0i t\u1eadp\n        </Link>\n      </div>\n\n      {!assignments?.length ? (\n        <div className=\"card\">\n          <div className=\"empty-state py-20\">\n            <ClipboardList size={48} className=\"text-gray-200 mb-4\"/>\n            <p className=\"text-gray-400 font-medium\">Ch\u01b0a c\u00f3 b\u00e0i t\u1eadp n\u00e0o</p>\n            <p className=\"text-gray-400 text-sm mt-1\">T\u1ea1o b\u00e0i t\u1eadp \u0111\u1ea7u ti\u00ean \u0111\u1ec3 giao cho h\u1ecdc vi\u00ean</p>\n            <Link href=\"/admin/assignments/new\" className=\"btn-primary mt-5\">\n              <Plus size={15}/> T\u1ea1o b\u00e0i t\u1eadp\n            </Link>\n          </div>\n        </div>\n      ) : (\n        <div className=\"space-y-3\">\n          {assignments.map(a => {\n            const qCount = (a.assignment_questions as any)?.[0]?.count ?? 0\n            const overdue = a.due_date && new Date(a.due_date) < new Date()\n            return (\n              <div key={a.id} className=\"card hover:shadow-md transition-shadow\">\n                <div className=\"card-body flex items-center justify-between gap-4\">\n                  <div className=\"flex-1 min-w-0\">\n                    <div className=\"flex items-center gap-3 mb-1\">\n                      <h3 className=\"font-semibold text-gray-900 truncate\">{a.title}</h3>\n                      <span className=\"badge badge-blue shrink-0\">{qCount} c\u00e2u h\u1ecfi</span>\n                      {a.due_date && (\n                        <span className={`badge shrink-0 ${overdue ? 'badge-red' : 'badge-yellow'}`}>\n                          {overdue ? 'Qu\u00e1 h\u1ea1n' : 'H\u1ea1n'}: {formatDate(a.due_date)}\n                        </span>\n                      )}\n                    </div>\n                    {a.description && (\n                      <p className=\"text-sm text-gray-500 truncate\">{a.description}</p>\n                    )}\n                    <p className=\"text-xs text-gray-400 mt-1\">T\u1ea1o: {formatDate(a.created_at)}</p>\n                  </div>\n                  <div className=\"flex items-center gap-2 shrink-0\">\n                    <Link href={`/admin/assignments/${a.id}`} className=\"btn-secondary text-sm\">\n                      Qu\u1ea3n l\u00fd\n                    </Link>\n                    <DeleteAssignmentBtn id={a.id} title={a.title}/>\n                  </div>\n                </div>\n              </div>\n            )\n          })}\n        </div>\n      )}\n    </div>\n  )\n}\n",
  "app/admin/assignments/new/page.tsx": "'use client'\n\nimport { useState, useTransition } from 'react'\nimport { useRouter } from 'next/navigation'\nimport { createAssignment } from '../actions'\nimport { ArrowLeft } from 'lucide-react'\nimport Link from 'next/link'\n\nexport default function NewAssignmentPage() {\n  const router = useRouter()\n  const [isPending, start] = useTransition()\n  const [error, setError]  = useState('')\n  const [form, setForm]    = useState({ title: '', description: '', due_date: '' })\n\n  function set(k: string, v: string) { setForm(f => ({ ...f, [k]: v })) }\n\n  function handleSubmit(e: React.FormEvent) {\n    e.preventDefault(); setError('')\n    const fd = new FormData()\n    Object.entries(form).forEach(([k, v]) => { if (v) fd.set(k, v) })\n    start(async () => {\n      const res = await createAssignment(fd)\n      if (res.error) { setError(res.error); return }\n      router.push(`/admin/assignments/${res.id}`)\n    })\n  }\n\n  return (\n    <div className=\"p-6 max-w-2xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <Link href=\"/admin/assignments\" className=\"flex items-center gap-1.5 text-sm text-gray-500 hover:text-gray-800 mb-1\">\n            <ArrowLeft size={14}/> Quay l\u1ea1i\n          </Link>\n          <h1 className=\"page-title\">T\u1ea1o b\u00e0i t\u1eadp m\u1edbi</h1>\n        </div>\n      </div>\n\n      {error && <div className=\"alert-error mb-5\">{error}</div>}\n\n      <div className=\"card\">\n        <div className=\"card-body\">\n          <form onSubmit={handleSubmit} className=\"space-y-5\">\n            <div>\n              <label className=\"label\">T\u00ean b\u00e0i t\u1eadp *</label>\n              <input className=\"input\" placeholder=\"VD: B\u00e0i t\u1eadp Algebra tu\u1ea7n 1\"\n                value={form.title} onChange={e => set('title', e.target.value)} required/>\n            </div>\n            <div>\n              <label className=\"label\">M\u00f4 t\u1ea3</label>\n              <textarea className=\"input\" rows={3}\n                placeholder=\"M\u00f4 t\u1ea3 ng\u1eafn v\u1ec1 b\u00e0i t\u1eadp n\u00e0y (tu\u1ef3 ch\u1ecdn)\"\n                value={form.description} onChange={e => set('description', e.target.value)}/>\n            </div>\n            <div>\n              <label className=\"label\">H\u1ea1n n\u1ed9p</label>\n              <input className=\"input\" type=\"datetime-local\"\n                value={form.due_date} onChange={e => set('due_date', e.target.value)}/>\n              <p className=\"text-xs text-gray-400 mt-1\">\u0110\u1ec3 tr\u1ed1ng n\u1ebfu kh\u00f4ng c\u00f3 h\u1ea1n c\u1ee5 th\u1ec3</p>\n            </div>\n            <div className=\"flex gap-3 pt-2\">\n              <Link href=\"/admin/assignments\" className=\"btn-secondary flex-1 justify-center\">Hu\u1ef7</Link>\n              <button type=\"submit\" disabled={isPending} className=\"btn-primary flex-1 justify-center\">\n                {isPending ? '\u0110ang t\u1ea1o\u2026' : 'T\u1ea1o & th\u00eam c\u00e2u h\u1ecfi \u2192'}\n              </button>\n            </div>\n          </form>\n        </div>\n      </div>\n    </div>\n  )\n}\n",
  "app/admin/assignments/[id]/page.tsx": "'use client'\n\nimport { useState, useEffect, useTransition } from 'react'\nimport { useParams, useRouter } from 'next/navigation'\nimport { createClient } from '@/lib/supabase/client'\nimport { addQuestionToAssignment, removeQuestionFromAssignment, updateAssignment } from '../actions'\nimport { ArrowLeft, Plus, Trash2, Search, Save } from 'lucide-react'\nimport Link from 'next/link'\nimport { formatDate } from '@/lib/utils'\nimport { MATH_SKILLS, RW_SKILLS } from '@/types'\n\nexport default function AssignmentDetailPage() {\n  const { id } = useParams<{ id: string }>()\n  const router  = useRouter()\n  const [isPending, start] = useTransition()\n\n  const [assignment, setAssignment]   = useState<any>(null)\n  const [aqList, setAqList]           = useState<any[]>([])   // questions in assignment\n  const [bankQuestions, setBankQ]     = useState<any[]>([])\n  const [search, setSearch]           = useState('')\n  const [domain, setDomain]           = useState('')\n  const [difficulty, setDifficulty]   = useState('')\n  const [tab, setTab]                 = useState<'questions'|'add'>('questions')\n  const [editing, setEditing]         = useState(false)\n  const [form, setForm]               = useState({ title: '', description: '', due_date: '' })\n  const [error, setError]             = useState('')\n  const [msg, setMsg]                 = useState('')\n\n  async function loadAssignment() {\n    const supabase = createClient()\n    const { data } = await supabase\n      .from('assignments').select('*').eq('id', id).single()\n    if (data) {\n      setAssignment(data)\n      setForm({ title: data.title, description: data.description ?? '', due_date: data.due_date ? data.due_date.slice(0,16) : '' })\n    }\n  }\n\n  async function loadAQ() {\n    const supabase = createClient()\n    const { data } = await supabase\n      .from('assignment_questions')\n      .select('position, questions(id, domain, skill, difficulty, content, correct_answer)')\n      .eq('assignment_id', id)\n      .order('position')\n    setAqList(data ?? [])\n  }\n\n  async function loadBank() {\n    const supabase = createClient()\n    let q = supabase.from('questions')\n      .select('id, domain, skill, difficulty, content, correct_answer')\n      .order('created_at', { ascending: false })\n      .limit(50)\n    if (domain)   q = (q as any).eq('domain', domain)\n    if (difficulty) q = (q as any).eq('difficulty', difficulty)\n    if (search.trim()) q = (q as any).ilike('content', `%${search}%`)\n    const { data } = await q\n    setBankQ(data ?? [])\n  }\n\n  useEffect(() => { loadAssignment(); loadAQ() }, [id])\n  useEffect(() => { if (tab === 'add') loadBank() }, [tab, domain, difficulty, search])\n\n  const addedIds = new Set(aqList.map(aq => aq.questions?.id))\n\n  async function handleAdd(questionId: string) {\n    const res = await addQuestionToAssignment(id, questionId)\n    if (res.error) { setError(res.error); return }\n    loadAQ()\n  }\n\n  async function handleRemove(questionId: string) {\n    await removeQuestionFromAssignment(id, questionId)\n    loadAQ()\n  }\n\n  async function handleSave() {\n    const fd = new FormData()\n    Object.entries(form).forEach(([k, v]) => { if (v) fd.set(k, v) })\n    start(async () => {\n      const res = await updateAssignment(id, fd)\n      if (res.error) { setError(res.error); return }\n      setEditing(false); setMsg('\u0110\u00e3 l\u01b0u!'); loadAssignment()\n      setTimeout(() => setMsg(''), 2000)\n    })\n  }\n\n  const diffColor: Record<string,string> = { Easy:'badge-green', Medium:'badge-yellow', Hard:'badge-red' }\n\n  if (!assignment) return <div className=\"p-6 text-gray-400\">\u0110ang t\u1ea3i\u2026</div>\n\n  return (\n    <div className=\"p-6 max-w-6xl mx-auto\">\n      {/* Header */}\n      <div className=\"page-header\">\n        <div>\n          <Link href=\"/admin/assignments\" className=\"flex items-center gap-1.5 text-sm text-gray-500 hover:text-gray-800 mb-1\">\n            <ArrowLeft size={14}/> Quay l\u1ea1i\n          </Link>\n          {editing ? (\n            <input className=\"input text-xl font-bold border-blue-300\" value={form.title}\n              onChange={e => setForm(f => ({ ...f, title: e.target.value }))}/>\n          ) : (\n            <h1 className=\"page-title\">{assignment.title}</h1>\n          )}\n          <p className=\"page-subtitle\">{aqList.length} c\u00e2u h\u1ecfi</p>\n        </div>\n        <div className=\"flex gap-2\">\n          {editing ? (\n            <>\n              <button onClick={() => setEditing(false)} className=\"btn-secondary\">Hu\u1ef7</button>\n              <button onClick={handleSave} disabled={isPending} className=\"btn-primary\">\n                <Save size={15}/> {isPending ? '\u0110ang l\u01b0u\u2026' : 'L\u01b0u'}\n              </button>\n            </>\n          ) : (\n            <button onClick={() => setEditing(true)} className=\"btn-secondary\">Ch\u1ec9nh s\u1eeda</button>\n          )}\n        </div>\n      </div>\n\n      {error && <div className=\"alert-error mb-4\">{error}</div>}\n      {msg   && <div className=\"alert-success mb-4\">{msg}</div>}\n\n      {/* Edit fields */}\n      {editing && (\n        <div className=\"card mb-5\">\n          <div className=\"card-body grid grid-cols-2 gap-4\">\n            <div>\n              <label className=\"label\">M\u00f4 t\u1ea3</label>\n              <textarea className=\"input\" rows={2} value={form.description}\n                onChange={e => setForm(f => ({ ...f, description: e.target.value }))}/>\n            </div>\n            <div>\n              <label className=\"label\">H\u1ea1n n\u1ed9p</label>\n              <input className=\"input\" type=\"datetime-local\" value={form.due_date}\n                onChange={e => setForm(f => ({ ...f, due_date: e.target.value }))}/>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Tabs */}\n      <div className=\"flex gap-1 mb-5 bg-gray-100 rounded-xl p-1 w-fit\">\n        {(['questions','add'] as const).map(t => (\n          <button key={t} onClick={() => setTab(t)}\n            className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${\n              tab === t ? 'bg-white text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'\n            }`}>\n            {t === 'questions' ? `C\u00e2u h\u1ecfi trong b\u00e0i (${aqList.length})` : '+ Th\u00eam t\u1eeb ng\u00e2n h\u00e0ng'}\n          </button>\n        ))}\n      </div>\n\n      {/* Tab: Questions in assignment */}\n      {tab === 'questions' && (\n        <div className=\"card\">\n          {aqList.length === 0 ? (\n            <div className=\"empty-state py-16\">\n              <p className=\"text-gray-400\">Ch\u01b0a c\u00f3 c\u00e2u h\u1ecfi n\u00e0o.</p>\n              <button onClick={() => setTab('add')} className=\"btn-primary mt-4\">\n                <Plus size={15}/> Th\u00eam c\u00e2u h\u1ecfi\n              </button>\n            </div>\n          ) : (\n            <div className=\"table-wrap\">\n              <table className=\"table\">\n                <thead>\n                  <tr><th className=\"w-10\">#</th><th>N\u1ed9i dung</th><th>Domain</th><th>\u0110\u1ed9 kh\u00f3</th><th>\u0110\u00e1p \u00e1n</th><th></th></tr>\n                </thead>\n                <tbody>\n                  {aqList.map((aq, i) => {\n                    const q = aq.questions\n                    return (\n                      <tr key={q?.id}>\n                        <td className=\"text-gray-400 text-xs\">{i + 1}</td>\n                        <td className=\"max-w-xs\">\n                          <p className=\"text-sm text-gray-800 truncate\">{q?.content?.slice(0, 80)}\u2026</p>\n                        </td>\n                        <td><span className=\"badge badge-blue text-xs\">{q?.domain === 'Math' ? 'Math' : 'R&W'}</span></td>\n                        <td><span className={`badge ${diffColor[q?.difficulty] ?? ''}`}>{q?.difficulty}</span></td>\n                        <td><span className=\"font-bold text-blue-600\">{q?.correct_answer}</span></td>\n                        <td>\n                          <button onClick={() => handleRemove(q?.id)}\n                            className=\"p-1.5 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors\">\n                            <Trash2 size={14}/>\n                          </button>\n                        </td>\n                      </tr>\n                    )\n                  })}\n                </tbody>\n              </table>\n            </div>\n          )}\n        </div>\n      )}\n\n      {/* Tab: Add from bank */}\n      {tab === 'add' && (\n        <div className=\"space-y-4\">\n          <div className=\"flex gap-3\">\n            <div className=\"relative flex-1 max-w-sm\">\n              <Search size={14} className=\"absolute left-3 top-1/2 -translate-y-1/2 text-gray-400\"/>\n              <input className=\"input pl-9\" placeholder=\"T\u00ecm c\u00e2u h\u1ecfi\u2026\"\n                value={search} onChange={e => setSearch(e.target.value)}/>\n            </div>\n            <select className=\"input w-44\" value={domain} onChange={e => { setDomain(e.target.value) }}>\n              <option value=\"\">T\u1ea5t c\u1ea3 domain</option>\n              <option value=\"Math\">Math</option>\n              <option value=\"Reading & Writing\">Reading &amp; Writing</option>\n            </select>\n            <select className=\"input w-36\" value={difficulty} onChange={e => setDifficulty(e.target.value)}>\n              <option value=\"\">T\u1ea5t c\u1ea3 \u0111\u1ed9 kh\u00f3</option>\n              <option value=\"Easy\">Easy</option>\n              <option value=\"Medium\">Medium</option>\n              <option value=\"Hard\">Hard</option>\n            </select>\n          </div>\n\n          <div className=\"card\">\n            <div className=\"table-wrap\">\n              <table className=\"table\">\n                <thead>\n                  <tr><th>N\u1ed9i dung</th><th>Domain</th><th>Skill</th><th>\u0110\u1ed9 kh\u00f3</th><th></th></tr>\n                </thead>\n                <tbody>\n                  {bankQuestions.length === 0 ? (\n                    <tr><td colSpan={5} className=\"text-center py-10 text-gray-400\">Kh\u00f4ng t\u00ecm th\u1ea5y c\u00e2u h\u1ecfi</td></tr>\n                  ) : bankQuestions.map(q => {\n                    const already = addedIds.has(q.id)\n                    return (\n                      <tr key={q.id}>\n                        <td className=\"max-w-xs\">\n                          <p className=\"text-sm text-gray-800 truncate\">{q.content?.slice(0, 70)}\u2026</p>\n                        </td>\n                        <td><span className=\"badge badge-blue text-xs\">{q.domain === 'Math' ? 'Math' : 'R&W'}</span></td>\n                        <td className=\"text-xs text-gray-500 max-w-[130px] truncate\">{q.skill}</td>\n                        <td><span className={`badge ${diffColor[q.difficulty] ?? ''}`}>{q.difficulty}</span></td>\n                        <td>\n                          {already ? (\n                            <span className=\"text-xs text-gray-400\">\u2713 \u0110\u00e3 c\u00f3</span>\n                          ) : (\n                            <button onClick={() => handleAdd(q.id)}\n                              className=\"btn-primary text-xs px-3 py-1.5\">\n                              <Plus size={13}/> Th\u00eam\n                            </button>\n                          )}\n                        </td>\n                      </tr>\n                    )\n                  })}\n                </tbody>\n              </table>\n            </div>\n          </div>\n        </div>\n      )}\n    </div>\n  )\n}\n",
  "app/admin/assignments/DeleteAssignmentBtn.tsx": "'use client'\n\nimport { useTransition } from 'react'\nimport { useRouter } from 'next/navigation'\nimport { deleteAssignment } from './actions'\nimport { Trash2 } from 'lucide-react'\n\ninterface Props { id: string; title: string }\n\nexport default function DeleteAssignmentBtn({ id, title }: Props) {\n  const [isPending, start] = useTransition()\n  const router = useRouter()\n\n  function handleDelete() {\n    if (!confirm(`Xo\u00e1 b\u00e0i t\u1eadp \"${title}\"? H\u00e0nh \u0111\u1ed9ng kh\u00f4ng th\u1ec3 ho\u00e0n t\u00e1c.`)) return\n    start(async () => {\n      await deleteAssignment(id)\n      router.refresh()\n    })\n  }\n\n  return (\n    <button onClick={handleDelete} disabled={isPending}\n      className=\"p-2 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors\">\n      <Trash2 size={15}/>\n    </button>\n  )\n}\n",
  "app/student/assignments/actions.ts": "'use server'\n\nimport { createAdminClient } from '@/lib/supabase/admin'\nimport { createClient } from '@/lib/supabase/server'\nimport { revalidatePath } from 'next/cache'\n\nexport async function startOrGetSession(assignmentId: string) {\n  const supabase = await createClient()\n  const { data: { user } } = await supabase.auth.getUser()\n  if (!user) return { error: 'Ch\u01b0a \u0111\u0103ng nh\u1eadp' }\n\n  const { data: profile } = await supabase\n    .from('users').select('id').eq('auth_id', user.id).single()\n  if (!profile) return { error: 'Kh\u00f4ng t\u00ecm th\u1ea5y user' }\n\n  // Check existing unfinished session\n  const { data: existing } = await supabase\n    .from('sessions')\n    .select('id')\n    .eq('user_id', profile.id)\n    .eq('assignment_id', assignmentId)\n    .is('finished_at', null)\n    .single()\n\n  if (existing) return { success: true, sessionId: existing.id }\n\n  // Count questions\n  const { count } = await supabase\n    .from('assignment_questions').select('*', { count: 'exact', head: true })\n    .eq('assignment_id', assignmentId)\n\n  const admin = createAdminClient()\n  const { data: session, error } = await admin.from('sessions').insert({\n    user_id:         profile.id,\n    assignment_id:   assignmentId,\n    total_questions: count ?? 0,\n  }).select('id').single()\n\n  if (error) return { error: error.message }\n  return { success: true, sessionId: session.id }\n}\n\nexport async function submitSession(\n  sessionId: string,\n  answers: Record<string, string>  // questionId -> chosen answer\n) {\n  const admin = createAdminClient()\n\n  // Get questions with correct answers\n  const { data: session } = await admin\n    .from('sessions').select('assignment_id').eq('id', sessionId).single()\n  if (!session) return { error: 'Session kh\u00f4ng t\u1ed3n t\u1ea1i' }\n\n  const { data: aqList } = await admin\n    .from('assignment_questions')\n    .select('question_id, questions(correct_answer)')\n    .eq('assignment_id', session.assignment_id)\n\n  if (!aqList) return { error: 'Kh\u00f4ng t\u00ecm th\u1ea5y c\u00e2u h\u1ecfi' }\n\n  // Calculate score\n  let correctCount = 0\n  const answerRows = aqList.map(aq => {\n    const chosen     = answers[aq.question_id] ?? null\n    const isCorrect  = chosen === (aq.questions as any)?.correct_answer\n    if (isCorrect) correctCount++\n    return {\n      session_id:    sessionId,\n      question_id:   aq.question_id,\n      chosen_answer: chosen,\n      is_correct:    isCorrect,\n    }\n  })\n\n  await admin.from('answers').insert(answerRows)\n  const score = aqList.length > 0 ? Math.round((correctCount / aqList.length) * 100) : 0\n\n  const { error } = await admin.from('sessions').update({\n    finished_at:   new Date().toISOString(),\n    correct_count: correctCount,\n    total_questions: aqList.length,\n    score,\n  }).eq('id', sessionId)\n\n  if (error) return { error: error.message }\n  revalidatePath('/student/results')\n  return { success: true, score, correctCount, total: aqList.length }\n}\n",
  "app/student/assignments/page.tsx": "import { createClient } from '@/lib/supabase/server'\nimport { formatDate } from '@/lib/utils'\nimport { redirect } from 'next/navigation'\nimport { ClipboardList, CheckCircle, Clock } from 'lucide-react'\nimport Link from 'next/link'\n\nexport default async function StudentAssignmentsPage() {\n  const supabase = await createClient()\n  const { data: { user } } = await supabase.auth.getUser()\n  if (!user) redirect('/login')\n\n  const { data: profile } = await supabase\n    .from('users').select('id').eq('auth_id', user.id).single()\n\n  const { data: assignments } = await supabase\n    .from('assignments')\n    .select('id, title, description, due_date, created_at, assignment_questions(count)')\n    .order('created_at', { ascending: false })\n\n  // Get user's completed sessions\n  const { data: sessions } = await supabase\n    .from('sessions')\n    .select('assignment_id, score, finished_at')\n    .eq('user_id', profile?.id ?? '')\n    .not('finished_at', 'is', null)\n\n  const doneMap = new Map(sessions?.map(s => [s.assignment_id, s]) ?? [])\n\n  return (\n    <div className=\"p-6 max-w-4xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <h1 className=\"page-title\">B\u00e0i t\u1eadp</h1>\n          <p className=\"page-subtitle\">Danh s\u00e1ch b\u00e0i t\u1eadp \u0111\u01b0\u1ee3c giao</p>\n        </div>\n      </div>\n\n      {!assignments?.length ? (\n        <div className=\"card\">\n          <div className=\"empty-state py-20\">\n            <ClipboardList size={48} className=\"text-gray-200 mb-4\"/>\n            <p className=\"text-gray-400 font-medium\">Ch\u01b0a c\u00f3 b\u00e0i t\u1eadp n\u00e0o</p>\n            <p className=\"text-gray-400 text-sm mt-1\">Gi\u00e1o vi\u00ean s\u1ebd giao b\u00e0i t\u1eadp s\u1edbm!</p>\n          </div>\n        </div>\n      ) : (\n        <div className=\"space-y-3\">\n          {assignments.map(a => {\n            const done     = doneMap.get(a.id)\n            const qCount   = (a.assignment_questions as any)?.[0]?.count ?? 0\n            const overdue  = a.due_date && !done && new Date(a.due_date) < new Date()\n            const pct      = done?.score ?? null\n\n            return (\n              <div key={a.id} className={`card transition-shadow hover:shadow-md ${done ? 'opacity-90' : ''}`}>\n                <div className=\"card-body flex items-center gap-5\">\n                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${\n                    done ? 'bg-emerald-100' : 'bg-blue-50'\n                  }`}>\n                    {done\n                      ? <CheckCircle size={22} className=\"text-emerald-600\"/>\n                      : <ClipboardList size={22} className=\"text-blue-600\"/>}\n                  </div>\n\n                  <div className=\"flex-1 min-w-0\">\n                    <div className=\"flex items-center gap-2 flex-wrap mb-1\">\n                      <h3 className=\"font-semibold text-gray-900\">{a.title}</h3>\n                      <span className=\"badge badge-blue\">{qCount} c\u00e2u</span>\n                      {done && pct !== null && (\n                        <span className={`badge ${pct >= 70 ? 'badge-green' : pct >= 50 ? 'badge-yellow' : 'badge-red'}`}>\n                          {pct}%\n                        </span>\n                      )}\n                      {overdue && <span className=\"badge badge-red\">Qu\u00e1 h\u1ea1n</span>}\n                    </div>\n                    {a.description && <p className=\"text-sm text-gray-500 truncate\">{a.description}</p>}\n                    {a.due_date && (\n                      <p className={`text-xs mt-1 flex items-center gap-1 ${overdue ? 'text-red-500' : 'text-gray-400'}`}>\n                        <Clock size={11}/> H\u1ea1n: {formatDate(a.due_date)}\n                      </p>\n                    )}\n                  </div>\n\n                  <div className=\"shrink-0\">\n                    {done ? (\n                      <Link href={`/student/results`} className=\"btn-secondary text-sm\">\n                        Xem k\u1ebft qu\u1ea3\n                      </Link>\n                    ) : qCount > 0 ? (\n                      <Link href={`/student/assignments/${a.id}`} className=\"btn-primary text-sm\">\n                        L\u00e0m b\u00e0i \u2192\n                      </Link>\n                    ) : (\n                      <span className=\"text-xs text-gray-400\">Ch\u01b0a c\u00f3 c\u00e2u h\u1ecfi</span>\n                    )}\n                  </div>\n                </div>\n              </div>\n            )\n          })}\n        </div>\n      )}\n    </div>\n  )\n}\n",
  "app/student/assignments/[id]/page.tsx": "'use client'\n\nimport { useState, useEffect, useTransition } from 'react'\nimport { useParams, useRouter } from 'next/navigation'\nimport { createClient } from '@/lib/supabase/client'\nimport { startOrGetSession, submitSession } from '../actions'\nimport { KaTeX } from '@/components/math/KaTeX'\nimport { CheckCircle, ChevronLeft, ChevronRight, Send } from 'lucide-react'\n\nexport default function TakeAssignmentPage() {\n  const { id } = useParams<{ id: string }>()\n  const router  = useRouter()\n  const [isPending, start] = useTransition()\n\n  const [assignment, setAssignment] = useState<any>(null)\n  const [questions, setQuestions]   = useState<any[]>([])\n  const [sessionId, setSessionId]   = useState<string>('')\n  const [answers, setAnswers]       = useState<Record<string, string>>({})\n  const [current, setCurrent]       = useState(0)\n  const [result, setResult]         = useState<any>(null)\n  const [loading, setLoading]       = useState(true)\n  const [error, setError]           = useState('')\n\n  useEffect(() => {\n    async function init() {\n      const supabase = createClient()\n      const { data: a } = await supabase\n        .from('assignments').select('id, title, description').eq('id', id).single()\n      setAssignment(a)\n\n      const { data: aqList } = await supabase\n        .from('assignment_questions')\n        .select('position, questions(id, content, option_a, option_b, option_c, option_d, correct_answer, explanation, domain, skill, difficulty)')\n        .eq('assignment_id', id)\n        .order('position')\n      setQuestions((aqList ?? []).map(aq => aq.questions).filter(Boolean))\n\n      const res = await startOrGetSession(id)\n      if (res.error) { setError(res.error); setLoading(false); return }\n      setSessionId(res.sessionId ?? '')\n      setLoading(false)\n    }\n    init()\n  }, [id])\n\n  function selectAnswer(questionId: string, letter: string) {\n    setAnswers(a => ({ ...a, [questionId]: letter }))\n  }\n\n  function handleSubmit() {\n    const unanswered = questions.filter(q => !answers[q.id]).length\n    if (unanswered > 0) {\n      if (!confirm(`B\u1ea1n c\u00f2n ${unanswered} c\u00e2u ch\u01b0a tr\u1ea3 l\u1eddi. N\u1ed9p b\u00e0i?`)) return\n    }\n    start(async () => {\n      const res = await submitSession(sessionId, answers)\n      if (res.error) { setError(res.error); return }\n      setResult(res)\n    })\n  }\n\n  const OPTIONS = ['A','B','C','D'] as const\n  const answered = Object.keys(answers).length\n\n  if (loading) return <div className=\"p-10 text-center text-gray-400\">\u0110ang t\u1ea3i\u2026</div>\n  if (error)   return <div className=\"p-10\"><div className=\"alert-error\">{error}</div></div>\n\n  // \u2500\u2500 Result screen \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  if (result) {\n    const pct = result.score\n    return (\n      <div className=\"p-6 max-w-2xl mx-auto\">\n        <div className=\"card text-center py-12\">\n          <div className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6 ${\n            pct >= 70 ? 'bg-emerald-100' : pct >= 50 ? 'bg-amber-100' : 'bg-red-100'\n          }`}>\n            <span className={`text-3xl font-bold ${\n              pct >= 70 ? 'text-emerald-600' : pct >= 50 ? 'text-amber-600' : 'text-red-600'\n            }`}>{pct}%</span>\n          </div>\n          <h2 className=\"text-xl font-bold text-gray-900 mb-2\">\n            {pct >= 70 ? '\ud83c\udf89 Xu\u1ea5t s\u1eafc!' : pct >= 50 ? '\ud83d\udc4d Kh\u00e1 t\u1ed1t!' : '\ud83d\udcaa C\u1ed1 g\u1eafng h\u01a1n nh\u00e9!'}\n          </h2>\n          <p className=\"text-gray-500 mb-1\">\n            \u0110\u00fang <span className=\"font-bold text-gray-900\">{result.correctCount}</span> / {result.total} c\u00e2u h\u1ecfi\n          </p>\n          <p className=\"text-sm text-gray-400 mb-8\">B\u00e0i: {assignment?.title}</p>\n\n          {/* Per-question review */}\n          <div className=\"text-left space-y-3 mb-8\">\n            {questions.map((q, i) => {\n              const chosen  = answers[q.id]\n              const correct = q.correct_answer\n              const isRight = chosen === correct\n              return (\n                <div key={q.id} className={`rounded-xl p-4 border ${isRight ? 'bg-emerald-50 border-emerald-200' : 'bg-red-50 border-red-200'}`}>\n                  <div className=\"flex items-start gap-2 mb-2\">\n                    <span className={`text-xs font-bold px-2 py-0.5 rounded-full shrink-0 mt-0.5 ${isRight ? 'bg-emerald-500 text-white' : 'bg-red-500 text-white'}`}>\n                      {i + 1}\n                    </span>\n                    <p className=\"text-sm text-gray-800 font-medium\">{q.content?.slice(0, 100)}\u2026</p>\n                  </div>\n                  <div className=\"flex gap-3 text-xs ml-7\">\n                    <span className={`font-semibold ${isRight ? 'text-emerald-700' : 'text-red-600'}`}>\n                      B\u1ea1n ch\u1ecdn: {chosen ?? '\u2014'}\n                    </span>\n                    {!isRight && (\n                      <span className=\"text-emerald-700 font-semibold\">\u0110\u00e1p \u00e1n \u0111\u00fang: {correct}</span>\n                    )}\n                  </div>\n                </div>\n              )\n            })}\n          </div>\n\n          <button onClick={() => router.push('/student/dashboard')} className=\"btn-primary\">\n            V\u1ec1 Dashboard\n          </button>\n        </div>\n      </div>\n    )\n  }\n\n  // \u2500\u2500 Question screen \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n  const q = questions[current]\n  if (!q) return null\n\n  return (\n    <div className=\"p-6 max-w-3xl mx-auto\">\n      {/* Progress header */}\n      <div className=\"mb-6\">\n        <div className=\"flex items-center justify-between mb-2\">\n          <h1 className=\"font-semibold text-gray-900\">{assignment?.title}</h1>\n          <span className=\"text-sm text-gray-500\">{answered}/{questions.length} \u0111\u00e3 tr\u1ea3 l\u1eddi</span>\n        </div>\n        <div className=\"progress-track\">\n          <div className=\"progress-fill bg-blue-500\"\n            style={{ width: `${questions.length > 0 ? ((current + 1) / questions.length) * 100 : 0}%` }}/>\n        </div>\n        <div className=\"flex justify-between text-xs text-gray-400 mt-1\">\n          <span>C\u00e2u {current + 1} / {questions.length}</span>\n          <span className={q.difficulty === 'Hard' ? 'text-red-500' : q.difficulty === 'Medium' ? 'text-amber-500' : 'text-emerald-500'}>\n            {q.difficulty}\n          </span>\n        </div>\n      </div>\n\n      {/* Question card */}\n      <div className=\"card mb-4\">\n        <div className=\"card-body\">\n          <div className=\"bg-gray-50 rounded-xl p-5 mb-5 text-sm leading-relaxed text-gray-800\">\n            <KaTeX text={q.content}/>\n          </div>\n\n          <div className=\"space-y-2.5\">\n            {OPTIONS.map(letter => {\n              const optKey  = `option_${letter.toLowerCase()}` as keyof typeof q\n              const text    = q[optKey]\n              const chosen  = answers[q.id] === letter\n              return (\n                <button key={letter} onClick={() => selectAnswer(q.id, letter)}\n                  className={`w-full flex items-start gap-3 p-4 rounded-xl border-2 text-left transition-all ${\n                    chosen\n                      ? 'border-blue-500 bg-blue-50'\n                      : 'border-gray-200 bg-white hover:border-blue-200 hover:bg-blue-50/30'\n                  }`}>\n                  <span className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold shrink-0 mt-0.5 ${\n                    chosen ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-600'\n                  }`}>{letter}</span>\n                  <span className=\"text-sm text-gray-800\"><KaTeX text={text}/></span>\n                </button>\n              )\n            })}\n          </div>\n        </div>\n      </div>\n\n      {/* Navigation */}\n      <div className=\"flex items-center justify-between\">\n        <button onClick={() => setCurrent(c => c - 1)} disabled={current === 0}\n          className=\"btn-secondary\"><ChevronLeft size={16}/> Tr\u01b0\u1edbc</button>\n\n        <div className=\"flex gap-1.5 flex-wrap max-w-sm justify-center\">\n          {questions.map((_, i) => (\n            <button key={i} onClick={() => setCurrent(i)}\n              className={`w-8 h-8 rounded-lg text-xs font-semibold transition-colors ${\n                i === current\n                  ? 'bg-blue-600 text-white'\n                  : answers[questions[i]?.id]\n                    ? 'bg-emerald-100 text-emerald-700'\n                    : 'bg-gray-100 text-gray-600 hover:bg-gray-200'\n              }`}>{i + 1}</button>\n          ))}\n        </div>\n\n        {current < questions.length - 1 ? (\n          <button onClick={() => setCurrent(c => c + 1)} className=\"btn-secondary\">\n            Ti\u1ebfp <ChevronRight size={16}/>\n          </button>\n        ) : (\n          <button onClick={handleSubmit} disabled={isPending}\n            className=\"btn-primary bg-emerald-600 hover:bg-emerald-700\">\n            <Send size={15}/> {isPending ? '\u0110ang n\u1ed9p\u2026' : 'N\u1ed9p b\u00e0i'}\n          </button>\n        )}\n      </div>\n    </div>\n  )\n}\n",
  "app/student/results/page.tsx": "import { createClient } from '@/lib/supabase/server'\nimport { redirect } from 'next/navigation'\nimport { formatDateTime } from '@/lib/utils'\nimport { TrendingUp, CheckCircle, XCircle } from 'lucide-react'\n\nexport default async function StudentResultsPage() {\n  const supabase = await createClient()\n  const { data: { user } } = await supabase.auth.getUser()\n  if (!user) redirect('/login')\n\n  const { data: profile } = await supabase\n    .from('users').select('id, full_name').eq('auth_id', user.id).single()\n\n  const { data: sessions } = await supabase\n    .from('sessions')\n    .select('id, score, total_questions, correct_count, started_at, finished_at, assignments(title)')\n    .eq('user_id', profile?.id ?? '')\n    .not('finished_at', 'is', null)\n    .order('finished_at', { ascending: false })\n\n  const avgScore = sessions?.length\n    ? Math.round(sessions.reduce((s, r) => s + (r.score ?? 0), 0) / sessions.length)\n    : null\n\n  return (\n    <div className=\"p-6 max-w-4xl mx-auto\">\n      <div className=\"page-header\">\n        <div>\n          <h1 className=\"page-title\">K\u1ebft qu\u1ea3 h\u1ecdc t\u1eadp</h1>\n          <p className=\"page-subtitle\">{sessions?.length ?? 0} b\u00e0i \u0111\u00e3 ho\u00e0n th\u00e0nh</p>\n        </div>\n      </div>\n\n      {/* Summary stats */}\n      {sessions && sessions.length > 0 && (\n        <div className=\"grid grid-cols-3 gap-4 mb-6\">\n          <div className=\"stat-card\">\n            <div className=\"stat-icon bg-blue-50\"><TrendingUp size={20} className=\"text-blue-600\"/></div>\n            <div>\n              <p className=\"text-xs text-gray-500 font-medium\">B\u00e0i \u0111\u00e3 l\u00e0m</p>\n              <p className=\"text-2xl font-bold text-gray-900 mt-0.5\">{sessions.length}</p>\n            </div>\n          </div>\n          <div className=\"stat-card\">\n            <div className=\"stat-icon bg-emerald-50\"><CheckCircle size={20} className=\"text-emerald-600\"/></div>\n            <div>\n              <p className=\"text-xs text-gray-500 font-medium\">\u0110i\u1ec3m TB</p>\n              <p className=\"text-2xl font-bold text-gray-900 mt-0.5\">{avgScore}%</p>\n            </div>\n          </div>\n          <div className=\"stat-card\">\n            <div className=\"stat-icon bg-purple-50\"><TrendingUp size={20} className=\"text-purple-600\"/></div>\n            <div>\n              <p className=\"text-xs text-gray-500 font-medium\">\u0110i\u1ec3m cao nh\u1ea5t</p>\n              <p className=\"text-2xl font-bold text-gray-900 mt-0.5\">\n                {Math.max(...(sessions.map(s => s.score ?? 0)))}%\n              </p>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Results list */}\n      {!sessions?.length ? (\n        <div className=\"card\">\n          <div className=\"empty-state py-20\">\n            <TrendingUp size={48} className=\"text-gray-200 mb-4\"/>\n            <p className=\"text-gray-400 font-medium\">Ch\u01b0a c\u00f3 k\u1ebft qu\u1ea3 n\u00e0o</p>\n            <p className=\"text-gray-400 text-sm mt-1\">Ho\u00e0n th\u00e0nh b\u00e0i t\u1eadp \u0111\u1ec3 xem k\u1ebft qu\u1ea3 \u1edf \u0111\u00e2y</p>\n          </div>\n        </div>\n      ) : (\n        <div className=\"card\">\n          <div className=\"table-wrap\">\n            <table className=\"table\">\n              <thead>\n                <tr>\n                  <th>B\u00e0i t\u1eadp</th>\n                  <th>\u0110i\u1ec3m</th>\n                  <th>\u0110\u00fang / T\u1ed5ng</th>\n                  <th>Th\u1eddi gian ho\u00e0n th\u00e0nh</th>\n                </tr>\n              </thead>\n              <tbody>\n                {sessions.map(s => {\n                  const pct = s.score ?? 0\n                  return (\n                    <tr key={s.id}>\n                      <td className=\"font-medium text-gray-900\">\n                        {(s.assignments as any)?.title ?? 'B\u00e0i luy\u1ec7n t\u1eadp'}\n                      </td>\n                      <td>\n                        <div className=\"flex items-center gap-2\">\n                          <div className=\"w-24 progress-track\">\n                            <div className={`progress-fill ${pct >= 70 ? 'bg-emerald-400' : pct >= 50 ? 'bg-amber-400' : 'bg-red-400'}`}\n                              style={{ width: `${pct}%` }}/>\n                          </div>\n                          <span className={`text-sm font-bold ${pct >= 70 ? 'text-emerald-600' : pct >= 50 ? 'text-amber-500' : 'text-red-500'}`}>\n                            {pct}%\n                          </span>\n                        </div>\n                      </td>\n                      <td className=\"text-sm text-gray-600\">\n                        <span className=\"text-emerald-600 font-semibold\">{s.correct_count}</span>\n                        <span className=\"text-gray-400\"> / {s.total_questions}</span>\n                      </td>\n                      <td className=\"text-xs text-gray-400\">\n                        {s.finished_at ? formatDateTime(s.finished_at) : '\u2014'}\n                      </td>\n                    </tr>\n                  )\n                })}\n              </tbody>\n            </table>\n          </div>\n        </div>\n      )}\n    </div>\n  )\n}\n"
};

let ok = 0, fail = 0;
for (const [relPath, content] of Object.entries(files)) {
  const fullPath = path.join(__dirname, relPath);
  try {
    fs.mkdirSync(path.dirname(fullPath), { recursive: true });
    fs.writeFileSync(fullPath, content, 'utf8');
    console.log('\x1b[32m  OK\x1b[0m', relPath);
    ok++;
  } catch(e) {
    console.log('\x1b[31m FAIL\x1b[0m', relPath, '-', e.message);
    fail++;
  }
}
console.log(`\n${ok} files written${fail ? ', ' + fail + ' failed' : '. All done! ✓'}`);
